import{_ as e,c as a,o as t,a1 as o}from"./chunks/framework.CQ_MtUmI.js";const g=JSON.parse('{"title":"Configure FFmpeg","description":"","frontmatter":{},"headers":[],"relativePath":"en-US/guide/ffmpeg.md","filePath":"en-US/guide/ffmpeg.md","lastUpdated":1717723122000}'),n={name:"en-US/guide/ffmpeg.md"},s=o(`<h1 id="configure-ffmpeg" tabindex="-1">Configure FFmpeg <a class="header-anchor" href="#configure-ffmpeg" aria-label="Permalink to &quot;Configure FFmpeg&quot;">​</a></h1><h2 id="what-is-ffmpeg" tabindex="-1">What is FFmpeg? <a class="header-anchor" href="#what-is-ffmpeg" aria-label="Permalink to &quot;What is FFmpeg?&quot;">​</a></h2><p><a href="https://ffmpeg.org/" target="_blank" rel="noreferrer">FFmpeg</a> is a well-known open-source audio and video processing library used in many audio and video encoding and decoding projects.</p><h2 id="why-use-ffmpeg" tabindex="-1">Why use FFmpeg? <a class="header-anchor" href="#why-use-ffmpeg" aria-label="Permalink to &quot;Why use FFmpeg?&quot;">​</a></h2><p>This project uses FFmpeg to encode and decode audio and video, allowing NapCat to handle audio and video files in formats supported by QQ.</p><p>If your Bot does not need to handle audio and video, you can choose not to install FFmpeg.</p><h2 id="install-ffmpeg" tabindex="-1">Install FFmpeg <a class="header-anchor" href="#install-ffmpeg" aria-label="Permalink to &quot;Install FFmpeg&quot;">​</a></h2><h3 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to &quot;Windows&quot;">​</a></h3><ol><li><p>Download the official licensed FFmpeg from <a href="https://www.gyan.dev/ffmpeg/builds/packages/ffmpeg-2024-02-15-git-a2cfd6062c-full_build.7z" target="_blank" rel="noreferrer">here</a>;</p></li><li><p>Extract the folder to a known location (e.g., <code>C:\\Program Files</code>) and rename it to <code>ffmpeg</code>;</p></li><li><p>Your <code>ffmpeg</code> folder structure should look like this:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ffmpeg</span></span>
<span class="line"><span>|___bin</span></span>
<span class="line"><span>|___|___ffmpeg.exe</span></span>
<span class="line"><span>|___|___ffplay.exe</span></span>
<span class="line"><span>|___\\___ffprobe.exe</span></span>
<span class="line"><span>|___doc</span></span>
<span class="line"><span>|___\\ ...</span></span>
<span class="line"><span>|___LICENSE</span></span>
<span class="line"><span>\\___README.txt</span></span></code></pre></div><div class="danger custom-block"><p class="custom-block-title">Note</p><p><strong>Make sure that the <code>bin</code> folder contains <code>ffmpeg.exe</code>, <code>ffplay.exe</code>, and <code>ffprobe.exe</code>!</strong> Otherwise, unexpected errors may occur.</p></div></li><li><p>Start QQNT, go to the LLOneBot settings page, select FFmpeg as the previously extracted <code>ffmpeg.exe</code> (in this example, the main FFmpeg program is located at <code>C:\\Program Files\\ffmpeg\\bin\\ffmpeg.exe</code>), and then click the &quot;Save&quot; button;</p></li><li><p>If no errors occur, FFmpeg is successfully configured. Congratulations!</p></li></ol><div class="tip custom-block"><p class="custom-block-title">If other programs also need to use FFmpeg</p><p>If other programs support manually selecting the FFmpeg location, simply configure it to use the FFmpeg used by NapCat.</p><p>If other programs do not support manually selecting the FFmpeg location, simply register the <code>bin</code> directory of FFmpeg to the system <code>PATH</code> variable (refer to <a href="https://zhuanlan.zhihu.com/p/595750538#:~:text=Step%203%3A%20%E7%8E%AF%E5%A2%83%E5%8F%98%E9%87%8F%20Path%20%E7%9A%84%E6%B7%BB%E5%8A%A0" target="_blank" rel="noreferrer">this tutorial</a>) .</p><p>If you have installed FFmpeg in the system variable, you can use FFmpeg normally whether or not you have configured the FFmpeg path in NapCat.</p></div><h3 id="linux" tabindex="-1">Linux <a class="header-anchor" href="#linux" aria-label="Permalink to &quot;Linux&quot;">​</a></h3><p>Use the package manager of your system to install <code>ffmpeg</code> directly.</p><h3 id="macos" tabindex="-1">macOS <a class="header-anchor" href="#macos" aria-label="Permalink to &quot;macOS&quot;">​</a></h3><p>You can install FFmpeg using <a href="https://brew.sh/" target="_blank" rel="noreferrer">Homebrew</a>, or you can manually download the binary files from <a href="https://evermeet.cx/ffmpeg/" target="_blank" rel="noreferrer">here</a> and install them.</p><p>Note that if you choose to install manually, make sure you download and install <a href="https://evermeet.cx/ffmpeg/#:~:text=static%20%2D%2Ddisable%2Dffplay-,FFmpeg,-ffmpeg%2D114296%2Dg5ff0eb34d2" target="_blank" rel="noreferrer">FFmpeg</a>, <a href="https://evermeet.cx/ffmpeg/#:~:text=external%20ffmpeg%20libraries-,FFprobe,-ffprobe%2D114296%2Dg5ff0eb34d2" target="_blank" rel="noreferrer">FFprobe</a>, and <a href="https://evermeet.cx/ffmpeg/#:~:text=external%20ffprobe%20libraries-,FFplay,-ffplay%2D113169%2Dge1c1dc8347" target="_blank" rel="noreferrer">FFplay</a>, otherwise unexpected errors may occur.</p>`,15),r=[s];function p(l,i,c,d,f,h){return t(),a("div",null,r)}const u=e(n,[["render",p]]);export{g as __pageData,u as default};
